// dropos-phase9.js
const fs=require('fs'),path=require('path'),{execSync}=require('child_process');
const files={"frontend/src/app/(public)/kiro/page.tsx":"\"use client\";\nimport { useState, useRef, useEffect, useCallback } from \"react\";\nimport { motion, AnimatePresence } from \"framer-motion\";\nimport Link from \"next/link\";\nimport { Send, Zap, ArrowRight, Loader2, Store, TrendingUp, Package, Star, X, Check } from \"lucide-react\";\n\nconst API = process.env.NEXT_PUBLIC_API_URL || \"https://dropos-v2.onrender.com/api\";\n\ninterface Msg {\n  id:   string;\n  role: \"user\" | \"KIRO\";\n  text: string;\n  done?: boolean;\n}\n\nconst STARTERS = [\n  \"I want to sell hair products\",\n  \"I sell electronics and gadgets\",\n  \"I want to start a fashion store\",\n  \"I sell beauty and skincare\",\n  \"Help me build a dropshipping store\",\n];\n\nconst DEMO_FLOW = [\n  { role:\"KIRO\" as const, text:\"Hey 👋 I'm KIRO — your AI business partner. What do you want to sell?\" },\n];\n\nconst FEATURES = [\n  { emoji:\"⚡\", label:\"60-second stores\",  desc:\"Type your niche. KIRO builds your store instantly.\" },\n  { emoji:\"🎯\", label:\"Winning products\",  desc:\"KIRO researches what sells before you import anything.\" },\n  { emoji:\"📣\", label:\"AI ad copy\",        desc:\"TikTok scripts, Instagram captions, WhatsApp messages — all written.\" },\n  { emoji:\"📊\", label:\"Plain English data\",desc:\"No charts. Just 'You made ₦84,000 today. Here's what to do next.'\" },\n];\n\nfunction AuthModal({ onClose, onSuccess }: { onClose: () => void; onSuccess: () => void }) {\n  const [mode, setMode]       = useState<\"login\"|\"register\">(\"register\");\n  const [email, setEmail]     = useState(\"\");\n  const [password, setPass]   = useState(\"\");\n  const [name, setName]       = useState(\"\");\n  const [loading, setLoading] = useState(false);\n  const [error, setError]     = useState(\"\");\n\n  const submit = async () => {\n    if (!email || !password) return;\n    setLoading(true); setError(\"\");\n    try {\n      const endpoint = mode === \"register\" ? \"/auth/register\" : \"/auth/login\";\n      const body = mode === \"register\" ? { name, email, password } : { email, password };\n      const res = await fetch(`${API}${endpoint}`, {\n        method: \"POST\", headers: { \"Content-Type\": \"application/json\" },\n        body: JSON.stringify(body),\n      });\n      const data = await res.json();\n      if (!res.ok) { setError(data.message || \"Something went wrong\"); return; }\n      if (data.data?.accessToken) {\n        localStorage.setItem(\"dropos-token\", data.data.accessToken);\n        onSuccess();\n      }\n    } catch { setError(\"Connection failed. Try again.\"); }\n    finally { setLoading(false); }\n  };\n\n  const inp = { width:\"100%\", padding:\"12px 16px\", borderRadius:12, border:\"1px solid rgba(255,255,255,0.1)\", background:\"rgba(255,255,255,0.05)\", color:\"#fff\", fontSize:14, outline:\"none\", fontFamily:\"inherit\", boxSizing:\"border-box\" as const };\n\n  return (\n    <div style={{ position:\"fixed\", inset:0, zIndex:9999, display:\"flex\", alignItems:\"center\", justifyContent:\"center\", padding:16, background:\"rgba(0,0,0,0.7)\", backdropFilter:\"blur(8px)\" }}\n      onClick={e => e.target === e.currentTarget && onClose()}>\n      <motion.div initial={{ opacity:0, scale:0.96, y:16 }} animate={{ opacity:1, scale:1, y:0 }}\n        style={{ width:\"100%\", maxWidth:400, borderRadius:24, background:\"#181230\", border:\"1px solid rgba(107,53,232,0.3)\", overflow:\"hidden\" }}>\n        <div style={{ padding:\"24px 24px 0\", textAlign:\"center\" }}>\n          <div style={{ width:40, height:40, borderRadius:12, background:\"linear-gradient(135deg,#6B35E8,#3D1C8A)\", display:\"flex\", alignItems:\"center\", justifyContent:\"center\", margin:\"0 auto 16px\" }}>\n            <Zap size={18} color=\"white\"/>\n          </div>\n          <h2 style={{ fontSize:20, fontWeight:900, color:\"#fff\", marginBottom:6, letterSpacing:\"-0.5px\" }}>Save your progress</h2>\n          <p style={{ fontSize:13, color:\"rgba(255,255,255,0.4)\", marginBottom:20 }}>Create your account to continue with KIRO. Takes 10 seconds.</p>\n          {/* Mode toggle */}\n          <div style={{ display:\"flex\", gap:4, padding:4, borderRadius:12, background:\"rgba(255,255,255,0.05)\", marginBottom:20 }}>\n            {([\"register\",\"login\"] as const).map(m => (\n              <button key={m} onClick={() => setMode(m)} style={{ flex:1, padding:\"8px\", borderRadius:8, border:\"none\", cursor:\"pointer\", fontSize:13, fontWeight:600, background:mode===m?\"rgba(107,53,232,0.4)\":\"transparent\", color:mode===m?\"#fff\":\"rgba(255,255,255,0.4)\", transition:\"all 0.15s\" }}>\n                {m === \"register\" ? \"Create account\" : \"Sign in\"}\n              </button>\n            ))}\n          </div>\n        </div>\n        <div style={{ padding:\"0 24px 24px\", display:\"flex\", flexDirection:\"column\", gap:10 }}>\n          {mode === \"register\" && (\n            <input value={name} onChange={e => setName(e.target.value)} placeholder=\"Your name\" style={inp}/>\n          )}\n          <input value={email} onChange={e => setEmail(e.target.value)} placeholder=\"you@example.com\" type=\"email\" style={inp}/>\n          <input value={password} onChange={e => setPass(e.target.value)} placeholder=\"Password\" type=\"password\" style={inp}\n            onKeyDown={e => e.key === \"Enter\" && submit()}/>\n          {error && <p style={{ fontSize:12, color:\"#EF4444\", textAlign:\"center\" }}>{error}</p>}\n          <button onClick={submit} disabled={loading || !email || !password}\n            style={{ padding:\"14px\", borderRadius:14, border:\"none\", background:\"linear-gradient(135deg,#6B35E8,#3D1C8A)\", color:\"#fff\", fontSize:15, fontWeight:800, cursor:\"pointer\", display:\"flex\", alignItems:\"center\", justifyContent:\"center\", gap:8, opacity:loading||!email||!password?0.6:1 }}>\n            {loading ? <Loader2 size={16} style={{ animation:\"spin 1s linear infinite\" }}/> : <Zap size={16}/>}\n            {loading ? \"...\" : mode === \"register\" ? \"Continue →\" : \"Sign in →\"}\n          </button>\n          <p style={{ fontSize:11, color:\"rgba(255,255,255,0.2)\", textAlign:\"center\" }}>\n            Your conversation is saved automatically. No card needed.\n          </p>\n        </div>\n      </motion.div>\n    </div>\n  );\n}\n\nexport default function PublicKIROPage() {\n  const [msgs,       setMsgs]       = useState<Msg[]>([...DEMO_FLOW.map((m,i) => ({ ...m, id:String(i), done:true }))]);\n  const [input,      setInput]      = useState(\"\");\n  const [loading,    setLoading]    = useState(false);\n  const [showAuth,   setShowAuth]   = useState(false);\n  const [authed,     setAuthed]     = useState(false);\n  const [msgCount,   setMsgCount]   = useState(0);\n  const bottomRef = useRef<HTMLDivElement>(null);\n  const inputRef  = useRef<HTMLTextAreaElement>(null);\n\n  useEffect(() => { bottomRef.current?.scrollIntoView({ behavior:\"smooth\" }); }, [msgs]);\n  useEffect(() => { if (localStorage.getItem(\"dropos-token\")) setAuthed(true); }, []);\n\n  const send = useCallback(async (text?: string) => {\n    const msg = (text || input).trim();\n    if (!msg || loading) return;\n    setInput(\"\");\n    const count = msgCount + 1;\n    setMsgCount(count);\n\n    // Show auth wall after 3 messages if not authed\n    if (!authed && count >= 3) {\n      setMsgs(p => [...p, { id:Date.now().toString(), role:\"user\", text:msg, done:true }]);\n      setTimeout(() => setShowAuth(true), 400);\n      return;\n    }\n\n    const uid = Date.now().toString();\n    const kid = (Date.now() + 1).toString();\n    setMsgs(p => [...p,\n      { id:uid, role:\"user\", text:msg, done:true },\n      { id:kid, role:\"KIRO\", text:\"\", done:false },\n    ]);\n    setLoading(true);\n\n    try {\n      const token = localStorage.getItem(\"dropos-token\") || \"\";\n      const res = await fetch(`${API}/kai/smart-chat`, {\n        method:\"POST\",\n        headers:{ \"Content-Type\":\"application/json\", ...(token ? { Authorization:`Bearer ${token}` } : {}) },\n        body: JSON.stringify({ message:msg, public:true }),\n      });\n      const data = await res.json();\n      const reply = data.data?.reply || data.reply || \"I am here! Tell me what you want to sell and I will build your store right now.\";\n      // Animate word by word\n      const words = reply.split(\" \");\n      let displayed = \"\";\n      for (let i = 0; i < words.length; i++) {\n        await new Promise(r => setTimeout(r, 12));\n        displayed += (i === 0 ? \"\" : \" \") + words[i];\n        setMsgs(p => p.map(m => m.id === kid ? { ...m, text:displayed } : m));\n        bottomRef.current?.scrollIntoView({ behavior:\"smooth\" });\n      }\n      setMsgs(p => p.map(m => m.id === kid ? { ...m, done:true } : m));\n    } catch {\n      setMsgs(p => p.map(m => m.id === kid ? { ...m, text:\"I am ready to help — try again or create your free account to get started.\", done:true } : m));\n    } finally { setLoading(false); }\n  }, [input, loading, msgCount, authed]);\n\n  return (\n    <div style={{ background:\"#07050F\", color:\"#fff\", minHeight:\"100vh\", fontFamily:\"'Plus Jakarta Sans', system-ui, sans-serif\" }}>\n      <style>{`\n        @import url('https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@400;500;600;700;800;900&display=swap');\n        @keyframes spin { to { transform:rotate(360deg); } }\n        * { box-sizing:border-box; }\n        .hide-scroll::-webkit-scrollbar { display:none; }\n      `}</style>\n\n      {/* Nav */}\n      <nav style={{ position:\"sticky\", top:0, zIndex:40, padding:\"0 20px\", height:56, display:\"flex\", alignItems:\"center\", justifyContent:\"space-between\", background:\"rgba(7,5,15,0.95)\", backdropFilter:\"blur(20px)\", borderBottom:\"1px solid rgba(255,255,255,0.06)\" }}>\n        <Link href=\"/\" style={{ textDecoration:\"none\", display:\"flex\", alignItems:\"center\", gap:8 }}>\n          <div style={{ width:28, height:28, borderRadius:9, background:\"linear-gradient(135deg,#6B35E8,#3D1C8A)\", display:\"flex\", alignItems:\"center\", justifyContent:\"center\" }}>\n            <Zap size={13} color=\"white\"/>\n          </div>\n          <span style={{ fontWeight:900, color:\"#fff\", fontSize:16 }}>Drop<span style={{ color:\"#8B5CF6\" }}>OS</span></span>\n        </Link>\n        <div style={{ display:\"flex\", gap:8 }}>\n          <Link href=\"/auth/login\" style={{ textDecoration:\"none\" }}>\n            <button style={{ padding:\"8px 16px\", borderRadius:10, border:\"1px solid rgba(255,255,255,0.1)\", background:\"transparent\", color:\"rgba(255,255,255,0.6)\", fontSize:13, cursor:\"pointer\", fontWeight:600 }}>Sign in</button>\n          </Link>\n          <Link href=\"/auth/register\" style={{ textDecoration:\"none\" }}>\n            <button style={{ padding:\"8px 16px\", borderRadius:10, border:\"none\", background:\"linear-gradient(135deg,#6B35E8,#3D1C8A)\", color:\"#fff\", fontSize:13, cursor:\"pointer\", fontWeight:700 }}>Start free</button>\n          </Link>\n        </div>\n      </nav>\n\n      <div style={{ maxWidth:480, margin:\"0 auto\", padding:\"20px 16px 100px\", display:\"flex\", flexDirection:\"column\", gap:0 }}>\n        {/* Hero text */}\n        <motion.div initial={{ opacity:0, y:16 }} animate={{ opacity:1, y:0 }} style={{ textAlign:\"center\", padding:\"24px 0 20px\" }}>\n          <div style={{ display:\"inline-flex\", alignItems:\"center\", gap:6, padding:\"4px 12px\", borderRadius:99, background:\"rgba(107,53,232,0.12)\", border:\"1px solid rgba(107,53,232,0.25)\", fontSize:11, fontWeight:700, color:\"#A78BFA\", marginBottom:14 }}>\n            <motion.div style={{ width:6, height:6, borderRadius:\"50%\", background:\"#10B981\" }} animate={{ opacity:[1,0.3,1] }} transition={{ duration:1.5, repeat:Infinity }}/>\n            KIRO is online\n          </div>\n          <h1 style={{ fontSize:\"clamp(28px,7vw,40px)\", fontWeight:900, letterSpacing:\"-2px\", lineHeight:1.1, margin:\"0 0 10px\" }}>\n            Your AI business<br/>partner.\n          </h1>\n          <p style={{ fontSize:14, color:\"rgba(255,255,255,0.4)\", lineHeight:1.6, margin:0 }}>\n            Tell KIRO what you sell. It builds your store, finds winning products, and writes your ads — right now.\n          </p>\n        </motion.div>\n\n        {/* Chat */}\n        <div style={{ display:\"flex\", flexDirection:\"column\", gap:12, marginBottom:12 }}>\n          {msgs.map(msg => (\n            <motion.div key={msg.id} initial={{ opacity:0, y:6 }} animate={{ opacity:1, y:0 }}\n              style={{ display:\"flex\", justifyContent:msg.role===\"user\"?\"flex-end\":\"flex-start\", gap:8, alignItems:\"flex-end\" }}>\n              {msg.role === \"KIRO\" && (\n                <div style={{ width:28, height:28, borderRadius:9, background:\"linear-gradient(135deg,#6B35E8,#3D1C8A)\", display:\"flex\", alignItems:\"center\", justifyContent:\"center\", flexShrink:0 }}>\n                  <Zap size={12} color=\"white\"/>\n                </div>\n              )}\n              <div style={{\n                maxWidth:\"82%\", padding:\"10px 14px\", fontSize:14, lineHeight:1.6, wordBreak:\"break-word\",\n                ...(msg.role === \"user\"\n                  ? { background:\"linear-gradient(135deg,#6B35E8,#3D1C8A)\", color:\"#fff\", borderRadius:\"18px 18px 4px 18px\" }\n                  : { background:\"rgba(255,255,255,0.05)\", color:\"rgba(255,255,255,0.88)\", borderRadius:\"4px 18px 18px 18px\", border:\"1px solid rgba(255,255,255,0.06)\" }\n                )\n              }}>\n                {msg.text || (msg.role === \"KIRO\" && !msg.done ? (\n                  <span style={{ display:\"inline-flex\", gap:3, alignItems:\"center\" }}>\n                    {[0,1,2].map(i => (\n                      <motion.span key={i} style={{ width:5, height:5, borderRadius:\"50%\", display:\"inline-block\", background:\"#8B5CF6\" }}\n                        animate={{ scale:[1,1.4,1], opacity:[0.4,1,0.4] }} transition={{ duration:0.8, delay:i*0.15, repeat:Infinity }}/>\n                    ))}\n                  </span>\n                ) : null)}\n                {msg.role === \"KIRO\" && !msg.done && msg.text && (\n                  <motion.span animate={{ opacity:[0,1] }} transition={{ duration:0.4, repeat:Infinity }} style={{ display:\"inline-block\", width:2, height:13, background:\"#8B5CF6\", marginLeft:2, verticalAlign:\"middle\" }}/>\n                )}\n              </div>\n            </motion.div>\n          ))}\n\n          {/* Auth nudge after 2 messages */}\n          {msgCount === 2 && !authed && (\n            <motion.div initial={{ opacity:0 }} animate={{ opacity:1 }}\n              style={{ padding:\"10px 14px\", borderRadius:14, background:\"rgba(107,53,232,0.08)\", border:\"1px solid rgba(107,53,232,0.2)\", fontSize:12, color:\"rgba(255,255,255,0.5)\", textAlign:\"center\" }}>\n              Create a free account to save your conversation and build your store 👇\n            </motion.div>\n          )}\n          <div ref={bottomRef}/>\n        </div>\n\n        {/* Quick starters */}\n        {msgs.length <= 2 && (\n          <div style={{ display:\"flex\", flexWrap:\"wrap\", gap:6, marginBottom:12 }}>\n            {STARTERS.map(s => (\n              <button key={s} onClick={() => send(s)}\n                style={{ padding:\"7px 14px\", borderRadius:99, border:\"1px solid rgba(255,255,255,0.1)\", background:\"rgba(255,255,255,0.04)\", color:\"rgba(255,255,255,0.65)\", fontSize:12, cursor:\"pointer\", fontWeight:500, transition:\"all 0.15s\" }}>\n                {s}\n              </button>\n            ))}\n          </div>\n        )}\n\n        {/* Features */}\n        {msgs.length <= 1 && (\n          <div style={{ display:\"grid\", gridTemplateColumns:\"1fr 1fr\", gap:8, marginTop:8 }}>\n            {FEATURES.map(f => (\n              <div key={f.label} style={{ padding:\"12px 14px\", borderRadius:14, background:\"rgba(255,255,255,0.03)\", border:\"1px solid rgba(255,255,255,0.06)\" }}>\n                <div style={{ fontSize:20, marginBottom:6 }}>{f.emoji}</div>\n                <p style={{ fontSize:12, fontWeight:700, color:\"rgba(255,255,255,0.8)\", marginBottom:3 }}>{f.label}</p>\n                <p style={{ fontSize:11, color:\"rgba(255,255,255,0.35)\", lineHeight:1.5 }}>{f.desc}</p>\n              </div>\n            ))}\n          </div>\n        )}\n      </div>\n\n      {/* Fixed input */}\n      <div style={{ position:\"fixed\", bottom:0, left:0, right:0, padding:\"12px 16px 20px\", background:\"rgba(7,5,15,0.97)\", backdropFilter:\"blur(20px)\", borderTop:\"1px solid rgba(255,255,255,0.06)\" }}>\n        <div style={{ maxWidth:480, margin:\"0 auto\" }}>\n          <div style={{ display:\"flex\", alignItems:\"flex-end\", gap:8, background:\"rgba(255,255,255,0.05)\", border:\"1px solid rgba(255,255,255,0.1)\", borderRadius:16, padding:\"8px 8px 8px 14px\" }}>\n            <textarea\n              ref={inputRef} value={input} onChange={e => setInput(e.target.value)}\n              onKeyDown={e => { if (e.key === \"Enter\" && !e.shiftKey) { e.preventDefault(); send(); } }}\n              placeholder=\"Tell KIRO what you want to sell...\" rows={1} disabled={loading}\n              style={{ flex:1, background:\"transparent\", border:\"none\", outline:\"none\", color:\"#fff\", fontSize:14, lineHeight:1.6, resize:\"none\", maxHeight:100, fontFamily:\"inherit\" }}\n              onInput={e => { const t = e.target as HTMLTextAreaElement; t.style.height=\"auto\"; t.style.height=Math.min(t.scrollHeight,100)+\"px\"; }}\n            />\n            <motion.button onClick={() => send()} disabled={!input.trim() || loading} whileTap={{ scale:0.92 }}\n              style={{ width:34, height:34, borderRadius:10, border:\"none\", cursor:input.trim()&&!loading?\"pointer\":\"not-allowed\", display:\"flex\", alignItems:\"center\", justifyContent:\"center\", flexShrink:0, background:input.trim()&&!loading?\"linear-gradient(135deg,#6B35E8,#3D1C8A)\":\"rgba(255,255,255,0.06)\", transition:\"all 0.15s\" }}>\n              {loading\n                ? <Loader2 size={14} color=\"rgba(255,255,255,0.5)\" style={{ animation:\"spin 1s linear infinite\" }}/>\n                : <svg width=\"14\" height=\"14\" viewBox=\"0 0 24 24\" fill=\"none\" stroke={input.trim()?\"white\":\"rgba(255,255,255,0.25)\"} strokeWidth=\"2\" strokeLinecap=\"round\" strokeLinejoin=\"round\"><line x1=\"22\" y1=\"2\" x2=\"11\" y2=\"13\"/><polygon points=\"22 2 15 22 11 13 2 9 22 2\"/></svg>\n              }\n            </motion.button>\n          </div>\n          <p style={{ fontSize:10, color:\"rgba(255,255,255,0.15)\", textAlign:\"center\", marginTop:8 }}>\n            Free to try · No credit card · Store live in 60 seconds\n          </p>\n        </div>\n      </div>\n\n      {/* Auth modal */}\n      <AnimatePresence>\n        {showAuth && (\n          <AuthModal\n            onClose={() => setShowAuth(false)}\n            onSuccess={() => { setShowAuth(false); setAuthed(true); }}\n          />\n        )}\n      </AnimatePresence>\n    </div>\n  );\n}\n","frontend/src/components/kai/KAIChat.tsx":"\"use client\";\nimport { useState, useRef, useEffect, useCallback } from \"react\";\nimport { motion, AnimatePresence }                  from \"framer-motion\";\nimport { useAuthStore }                             from \"../../store/auth.store\";\nimport { api }                                      from \"../../lib/api\";\nimport {\n  Send, Sparkles, Copy, Check, ThumbsUp, RotateCcw,\n  Loader2, Plus, X, Zap, BarChart2, ShoppingCart,\n  Package, TrendingUp, Image, Paperclip, Mic,\n} from \"lucide-react\";\nimport toast from \"react-hot-toast\";\n\ninterface Message {\n  id:          string;\n  role:        \"user\" | \"KIRO\";\n  content:     string;\n  timestamp:   Date;\n  isStreaming?: boolean;\n  actions?:    Array<{ label: string; action: string; payload?: any }>;\n  dataCard?:   any;\n  type?:       \"text\" | \"action_result\" | \"error\";\n}\n\nconst QUICK_CHIPS = [\n  { icon: \"📊\", label: \"Sales today\",           prompt: \"What are my sales today and how do I grow them?\" },\n  { icon: \"📦\", label: \"Pending orders\",         prompt: \"Show me orders that need fulfillment right now\" },\n  { icon: \"🔥\", label: \"Trending products\",      prompt: \"What products are trending right now? Show me demand data.\" },\n  { icon: \"✍️\",  label: \"TikTok script\",          prompt: \"Write a TikTok script for my best-selling product\" },\n  { icon: \"🎟️\", label: \"Create coupon\",          prompt: \"Create a 15% off coupon code for new customers\" },\n  { icon: \"⚡\", label: \"Flash sale\",             prompt: \"Set up a 3-hour flash sale on my top products at 20% off\" },\n  { icon: \"📈\", label: \"Revenue forecast\",       prompt: \"Forecast my revenue for next 30 days based on current trends\" },\n  { icon: \"🎯\", label: \"Grow my store\",          prompt: \"Audit my store and tell me the 3 things I should fix right now\" },\n];\n\nfunction KIROAvatar({ size = 32 }: { size?: number }) {\n  return (\n    <div style={{ width: size, height: size, borderRadius: size * 0.3, background: \"linear-gradient(145deg,#6B35E8,#1A0D3D)\", display: \"flex\", alignItems: \"center\", justifyContent: \"center\", flexShrink: 0, boxShadow: \"0 2px 12px rgba(107,53,232,0.4)\" }}>\n      <Zap size={size * 0.45} color=\"white\" />\n    </div>\n  );\n}\n\nfunction TypingIndicator() {\n  return (\n    <div style={{ display: \"flex\", alignItems: \"center\", gap: 4, padding: \"10px 14px\", background: \"rgba(255,255,255,0.04)\", borderRadius: 14, width: \"fit-content\" }}>\n      {[0, 1, 2].map(i => (\n        <motion.div key={i} style={{ width: 5, height: 5, borderRadius: \"50%\", background: \"#8B5CF6\" }}\n          animate={{ scale: [1, 1.4, 1], opacity: [0.4, 1, 0.4] }}\n          transition={{ duration: 0.9, delay: i * 0.18, repeat: Infinity }} />\n      ))}\n    </div>\n  );\n}\n\nfunction ActionButtons({ actions, onAction }: { actions: Array<{ label: string; action: string; payload?: any }>; onAction: (a: any) => void }) {\n  if (!actions?.length) return null;\n  const ACTION_ICONS: Record<string, string> = {\n    create_coupon:      \"🎟️\",\n    update_price:       \"💰\",\n    update_order_status:\"📦\",\n    create_product:     \"➕\",\n    send_broadcast:     \"📣\",\n    run_flash_sale:     \"⚡\",\n    navigate:           \"→\",\n    update_goal:        \"🎯\",\n  };\n  return (\n    <div style={{ display: \"flex\", flexWrap: \"wrap\", gap: 6, marginTop: 10 }}>\n      {actions.map((a, i) => (\n        <button key={i} onClick={() => onAction(a)}\n          style={{ display:\"flex\", alignItems:\"center\", gap:5, padding: \"6px 14px\", borderRadius: 20, fontSize: 12, fontWeight: 600, cursor: \"pointer\", border: \"1px solid rgba(107,53,232,0.35)\", background: \"rgba(107,53,232,0.1)\", color: \"#A78BFA\", transition: \"all 0.15s\" }}>\n          {ACTION_ICONS[a.action] && <span>{ACTION_ICONS[a.action]}</span>}\n          {a.label}\n        </button>\n      ))}\n    </div>\n  );\n}\n\nfunction MessageBubble({ msg, onAction, onCopy }: { msg: Message; onAction: (a: any) => void; onCopy: (t: string) => void }) {\n  const isKIRO = msg.role === \"KIRO\";\n  const [copied, setCopied] = useState(false);\n\n  const handleCopy = () => {\n    navigator.clipboard.writeText(msg.content);\n    setCopied(true);\n    setTimeout(() => setCopied(false), 2000);\n    onCopy(msg.id);\n  };\n\n  if (isKIRO) {\n    return (\n      <motion.div initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} style={{ display: \"flex\", gap: 10, alignItems: \"flex-start\", maxWidth: \"100%\" }}>\n        <KIROAvatar size={28} />\n        <div style={{ flex: 1, minWidth: 0 }}>\n          {msg.isStreaming && msg.content === \"\" ? <TypingIndicator /> : (\n            <div>\n              {/* Render markdown-ish content cleanly */}\n              <div style={{ fontSize: 14, lineHeight: 1.7, color: \"rgba(255,255,255,0.88)\", whiteSpace: \"pre-wrap\", wordBreak: \"break-word\" }}>\n                {msg.content.split(\"\\n\").map((line, i) => {\n                  if (line.startsWith(\"## \")) return <p key={i} style={{ fontWeight: 800, fontSize: 15, color: \"#fff\", margin: \"12px 0 4px\" }}>{line.slice(3)}</p>;\n                  if (line.startsWith(\"# \")) return <p key={i} style={{ fontWeight: 900, fontSize: 16, color: \"#fff\", margin: \"14px 0 6px\" }}>{line.slice(2)}</p>;\n                  if (line.startsWith(\"**\") && line.endsWith(\"**\")) return <p key={i} style={{ fontWeight: 700, color: \"#fff\" }}>{line.slice(2, -2)}</p>;\n                  if (line.startsWith(\"- \") || line.startsWith(\"• \")) return <p key={i} style={{ paddingLeft: 16, position: \"relative\", color: \"rgba(255,255,255,0.75)\" }}><span style={{ position: \"absolute\", left: 4, color: \"#8B5CF6\" }}>•</span>{line.slice(2)}</p>;\n                  if (/^\\d+\\./.test(line)) return <p key={i} style={{ paddingLeft: 20, color: \"rgba(255,255,255,0.75)\" }}>{line}</p>;\n                  if (line === \"\") return <br key={i} />;\n                  return <span key={i}>{line}{i < msg.content.split(\"\\n\").length - 1 ? \"\\n\" : \"\"}</span>;\n                })}\n                {msg.isStreaming && <motion.span animate={{ opacity: [0, 1] }} transition={{ duration: 0.5, repeat: Infinity }} style={{ display: \"inline-block\", width: 2, height: 14, background: \"#8B5CF6\", marginLeft: 2, verticalAlign: \"middle\" }} />}\n              </div>\n              {!msg.isStreaming && msg.content && (\n                <button onClick={handleCopy} style={{ marginTop: 6, display: \"flex\", alignItems: \"center\", gap: 4, fontSize: 11, color: \"rgba(255,255,255,0.25)\", background: \"none\", border: \"none\", cursor: \"pointer\", padding: \"2px 0\" }}>\n                  {copied ? <><Check size={10} /> Copied</> : <><Copy size={10} /> Copy</>}\n                </button>\n              )}\n              {!msg.isStreaming && msg.actions && <ActionButtons actions={msg.actions} onAction={onAction} />}\n            </div>\n          )}\n        </div>\n      </motion.div>\n    );\n  }\n\n  return (\n    <motion.div initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} style={{ display: \"flex\", justifyContent: \"flex-end\" }}>\n      <div style={{ maxWidth: \"75%\", padding: \"10px 14px\", borderRadius: \"18px 18px 4px 18px\", background: \"linear-gradient(135deg,#6B35E8,#3D1C8A)\", fontSize: 14, lineHeight: 1.6, color: \"#fff\", wordBreak: \"break-word\" }}>\n        {msg.content}\n      </div>\n    </motion.div>\n  );\n}\n\ninterface KIROChatProps {\n  className?:        string;\n  storeId?:          string;\n  initialMessage?:   string;\n  compact?:          boolean;\n}\n\nexport default function KIROChat({ className, storeId: propStoreId, initialMessage, compact }: KIROChatProps) {\n  const { user }           = useAuthStore();\n  const effectiveStoreId   = propStoreId || user?.stores?.[0]?.id || \"\";\n  const [messages, setMessages] = useState<Message[]>([]);\n  const [input,    setInput]    = useState(initialMessage || \"\");\n  const [loading,  setLoading]  = useState(false);\n  const [sessionId, setSessionId] = useState(\"\");\n  const bottomRef  = useRef<HTMLDivElement>(null);\n  const inputRef   = useRef<HTMLTextAreaElement>(null);\n  const abortRef   = useRef<AbortController | null>(null);\n\n  useEffect(() => {\n    bottomRef.current?.scrollIntoView({ behavior: \"smooth\" });\n  }, [messages]);\n\n  useEffect(() => {\n    if (initialMessage) { setInput(initialMessage); inputRef.current?.focus(); }\n  }, [initialMessage]);\n\n  // ── Execute KIRO action ────────────────────────────────────\n  const executeAction = useCallback(async (action: { action: string; payload?: any; label: string }) => {\n    const confirmMsg: Message = {\n      id: Date.now().toString(), role: \"user\",\n      content: `Execute: ${action.label}`, timestamp: new Date(),\n    };\n    const resultPlaceholder: Message = {\n      id: (Date.now() + 1).toString(), role: \"KIRO\",\n      content: \"\", timestamp: new Date(), isStreaming: true,\n    };\n    setMessages(prev => [...prev, confirmMsg, resultPlaceholder]);\n    setLoading(true);\n\n    try {\n      const res = await api.post(\"/kai/action\", {\n        storeId: effectiveStoreId,\n        actions: [{\n          id:       Date.now().toString(),\n          type:     action.action,\n          payload:  action.payload || {},\n          approved: true,\n        }],\n      });\n      const results = res.data?.data || [];\n      const result  = results[0]?.result\n        ? JSON.stringify(results[0].result).slice(0, 200)\n        : results[0]?.error || \"Done.\";\n      setMessages(prev => prev.map(m =>\n        m.id === resultPlaceholder.id ? { ...m, content: result, isStreaming: false } : m\n      ));\n      toast.success(`KIRO: ${action.label} complete`);\n    } catch (err: any) {\n      setMessages(prev => prev.map(m =>\n        m.id === resultPlaceholder.id ? { ...m, content: \"I could not complete that action - the backend may be offline.\", isStreaming: false } : m\n      ));\n    } finally {\n      setLoading(false);\n    }\n  }, [effectiveStoreId]);\n\n  // ── Send message with real SSE streaming ──────────────────\n  const send = useCallback(async (overrideText?: string) => {\n    const text = (overrideText || input).trim();\n    if (!text || loading) return;\n    setInput(\"\");\n\n    const userMsg: Message = {\n      id: Date.now().toString(), role: \"user\",\n      content: text, timestamp: new Date(),\n    };\n    const kiroPlaceholder: Message = {\n      id: (Date.now() + 1).toString(), role: \"KIRO\",\n      content: \"\", timestamp: new Date(), isStreaming: true,\n    };\n\n    setMessages(prev => [...prev, userMsg, kiroPlaceholder]);\n    setLoading(true);\n\n    try {\n      abortRef.current = new AbortController();\n\n      // Try real SSE streaming first\n      const streamRes = await fetch(\n        `${process.env.NEXT_PUBLIC_API_URL || \"https://dropos-v2.onrender.com/api\"}/kai/smart-chat`,\n        {\n          method:  \"POST\",\n          headers: {\n            \"Content-Type\":  \"application/json\",\n            \"Authorization\": `Bearer ${useAuthStore.getState().accessToken || \"\"}`,\n            \"Accept\":        \"text/event-stream\",\n          },\n          body:   JSON.stringify({ message: text, storeId: effectiveStoreId, sessionId: sessionId || undefined }),\n          signal: abortRef.current.signal,\n        }\n      );\n\n      if (streamRes.ok && streamRes.headers.get(\"content-type\")?.includes(\"text/event-stream\")) {\n        // Real SSE streaming\n        const reader  = streamRes.body!.getReader();\n        const decoder = new TextDecoder();\n        let fullText  = \"\";\n        let actions: any[] = [];\n\n        while (true) {\n          const { done, value } = await reader.read();\n          if (done) break;\n\n          const chunk = decoder.decode(value, { stream: true });\n          const lines = chunk.split(\"\\n\");\n\n          for (const line of lines) {\n            if (line.startsWith(\"data: \")) {\n              const data = line.slice(6).trim();\n              if (data === \"[DONE]\") {\n                setMessages(prev => prev.map(m =>\n                  m.id === kiroPlaceholder.id ? { ...m, content: fullText, isStreaming: false, actions } : m\n                ));\n                break;\n              }\n              try {\n                const parsed = JSON.parse(data);\n                if (parsed.type === \"text_delta\" && parsed.delta) {\n                  fullText += parsed.delta;\n                  setMessages(prev => prev.map(m =>\n                    m.id === kiroPlaceholder.id ? { ...m, content: fullText, isStreaming: true } : m\n                  ));\n                  bottomRef.current?.scrollIntoView({ behavior: \"smooth\" });\n                } else if (parsed.type === \"actions\") {\n                  actions = parsed.actions || [];\n                } else if (parsed.session_id && !sessionId) {\n                  setSessionId(parsed.session_id);\n                }\n              } catch (_) {\n                // Non-JSON line, skip\n              }\n            }\n          }\n        }\n      } else {\n        // Fallback: non-streaming endpoint\n        const res = await api.post(\"/kai/smart-chat\", {\n          message: text, storeId: effectiveStoreId, sessionId: sessionId || undefined,\n        });\n        const { reply, session_id, actions = [] } = res.data.data || res.data;\n        if (session_id && !sessionId) setSessionId(session_id);\n\n        // Animate word-by-word for non-streaming fallback\n        const words = (reply || \"I am here. How can I help?\").split(\" \");\n        let displayed = \"\";\n        for (let i = 0; i < words.length; i++) {\n          await new Promise(r => setTimeout(r, 15 + Math.random() * 8));\n          displayed += (i === 0 ? \"\" : \" \") + words[i];\n          setMessages(prev => prev.map(m =>\n            m.id === kiroPlaceholder.id ? { ...m, content: displayed, isStreaming: true } : m\n          ));\n          bottomRef.current?.scrollIntoView({ behavior: \"smooth\" });\n        }\n        setMessages(prev => prev.map(m =>\n          m.id === kiroPlaceholder.id ? { ...m, content: reply || \"I am here. How can I help?\", isStreaming: false, actions } : m\n        ));\n      }\n    } catch (err: any) {\n      if (err.name === \"AbortError\") return;\n      setMessages(prev => prev.map(m =>\n        m.id === kiroPlaceholder.id ? { ...m, content: \"Something went wrong. Please check your connection and try again.\", isStreaming: false } : m\n      ));\n    } finally {\n      setLoading(false);\n    }\n  }, [input, loading, effectiveStoreId, sessionId]);\n\n  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {\n    if (e.key === \"Enter\" && !e.shiftKey) { e.preventDefault(); send(); }\n  };\n\n  const clear = () => { setMessages([]); setSessionId(\"\"); };\n  const isEmpty = messages.length === 0;\n\n  return (\n    <div className={`flex flex-col ${className || \"h-full\"}`}\n      style={{ background: \"#0a0a14\", fontFamily: \"'Plus Jakarta Sans', system-ui, sans-serif\" }}>\n\n      {/* Header */}\n      <div style={{ display: \"flex\", alignItems: \"center\", justifyContent: \"space-between\", padding: \"12px 16px\", borderBottom: \"1px solid rgba(255,255,255,0.06)\", flexShrink: 0 }}>\n        <div style={{ display: \"flex\", alignItems: \"center\", gap: 10 }}>\n          <KIROAvatar size={30} />\n          <div>\n            <p style={{ fontSize: 14, fontWeight: 800, color: \"#fff\", letterSpacing: \"-0.02em\" }}>KIRO</p>\n            <div style={{ display: \"flex\", alignItems: \"center\", gap: 5 }}>\n              <motion.div style={{ width: 6, height: 6, borderRadius: \"50%\", background: \"#10B981\" }}\n                animate={{ opacity: [1, 0.4, 1] }} transition={{ duration: 2, repeat: Infinity }} />\n              <p style={{ fontSize: 11, color: \"rgba(255,255,255,0.35)\" }}>Your AI business partner</p>\n            </div>\n          </div>\n        </div>\n        {messages.length > 0 && (\n          <button onClick={clear} style={{ padding: \"6px 10px\", borderRadius: 8, border: \"1px solid rgba(255,255,255,0.08)\", background: \"transparent\", color: \"rgba(255,255,255,0.35)\", fontSize: 11, cursor: \"pointer\" }}>\n            Clear\n          </button>\n        )}\n      </div>\n\n      {/* Messages */}\n      <div className=\"hide-scroll\" style={{ flex: 1, overflowY: \"auto\", padding: \"16px\", display: \"flex\", flexDirection: \"column\", gap: 16 }}>\n        {isEmpty ? (\n          <div style={{ flex: 1, display: \"flex\", flexDirection: \"column\", alignItems: \"center\", justifyContent: \"center\", textAlign: \"center\", padding: \"24px 16px\" }}>\n            <motion.div initial={{ scale: 0.8, opacity: 0 }} animate={{ scale: 1, opacity: 1 }}\n              style={{ width: 64, height: 64, borderRadius: 20, background: \"linear-gradient(145deg,#6B35E8,#1A0D3D)\", display: \"flex\", alignItems: \"center\", justifyContent: \"center\", marginBottom: 16, boxShadow: \"0 8px 32px rgba(107,53,232,0.4)\" }}>\n              <Zap size={28} color=\"white\" />\n            </motion.div>\n            <p style={{ fontSize: 18, fontWeight: 800, color: \"#fff\", marginBottom: 8, letterSpacing: \"-0.03em\" }}>\n              Good {new Date().getHours() < 12 ? \"morning\" : new Date().getHours() < 17 ? \"afternoon\" : \"evening\"} 👋\n            </p>\n            <p style={{ fontSize: 13, color: \"rgba(255,255,255,0.38)\", marginBottom: 24, maxWidth: 300, lineHeight: 1.6 }}>\n              I am KIRO. I run your store, find winning products, write your ads, and grow your revenue. What do you need?\n            </p>\n            <div style={{ display: \"grid\", gridTemplateColumns: \"1fr 1fr\", gap: 8, width: \"100%\", maxWidth: 380 }}>\n              {QUICK_CHIPS.map(chip => (\n                <button key={chip.label} onClick={() => send(chip.prompt)}\n                  style={{ padding: \"10px 12px\", borderRadius: 12, border: \"1px solid rgba(255,255,255,0.07)\", background: \"rgba(255,255,255,0.03)\", cursor: \"pointer\", textAlign: \"left\", transition: \"all 0.15s\" }}\n                  onMouseEnter={e => (e.currentTarget.style.borderColor = \"rgba(107,53,232,0.4)\")}\n                  onMouseLeave={e => (e.currentTarget.style.borderColor = \"rgba(255,255,255,0.07)\")}>\n                  <span style={{ fontSize: 16, display: \"block\", marginBottom: 2 }}>{chip.icon}</span>\n                  <span style={{ fontSize: 11, fontWeight: 600, color: \"rgba(255,255,255,0.6)\" }}>{chip.label}</span>\n                </button>\n              ))}\n            </div>\n          </div>\n        ) : (\n          messages.map(msg => (\n            <MessageBubble key={msg.id} msg={msg} onAction={executeAction} onCopy={() => {}} />\n          ))\n        )}\n        <div ref={bottomRef} />\n      </div>\n\n      {/* Input */}\n      <div style={{ padding: \"12px 16px\", borderTop: \"1px solid rgba(255,255,255,0.06)\", flexShrink: 0 }}>\n        <div style={{ display: \"flex\", alignItems: \"flex-end\", gap: 8, background: \"rgba(255,255,255,0.05)\", border: \"1px solid rgba(255,255,255,0.1)\", borderRadius: 16, padding: \"8px 8px 8px 14px\", transition: \"border-color 0.15s\" }}>\n          <textarea\n            ref={inputRef}\n            value={input}\n            onChange={e => setInput(e.target.value)}\n            onKeyDown={handleKeyDown}\n            placeholder=\"Ask KIRO anything about your store...\"\n            rows={1}\n            disabled={loading}\n            style={{ flex: 1, background: \"transparent\", border: \"none\", outline: \"none\", color: \"#fff\", fontSize: 14, lineHeight: 1.6, resize: \"none\", maxHeight: 120, fontFamily: \"inherit\" }}\n            onInput={e => {\n              const t = e.target as HTMLTextAreaElement;\n              t.style.height = \"auto\";\n              t.style.height = Math.min(t.scrollHeight, 120) + \"px\";\n            }}\n          />\n          <motion.button\n            onClick={() => send()}\n            disabled={!input.trim() || loading}\n            whileTap={{ scale: 0.92 }}\n            style={{ width: 34, height: 34, borderRadius: 10, border: \"none\", cursor: input.trim() && !loading ? \"pointer\" : \"not-allowed\", display: \"flex\", alignItems: \"center\", justifyContent: \"center\", flexShrink: 0, background: input.trim() && !loading ? \"linear-gradient(135deg,#6B35E8,#3D1C8A)\" : \"rgba(255,255,255,0.06)\", transition: \"all 0.15s\" }}>\n            {loading\n              ? <Loader2 size={15} color=\"rgba(255,255,255,0.5)\" style={{ animation: \"spin 1s linear infinite\" }} />\n              : <Send size={14} color={input.trim() ? \"white\" : \"rgba(255,255,255,0.25)\"} />\n            }\n          </motion.button>\n        </div>\n        <p style={{ fontSize: 10, color: \"rgba(255,255,255,0.15)\", textAlign: \"center\", marginTop: 8 }}>\n          KIRO can make mistakes. Always verify important decisions.\n        </p>\n      </div>\n    </div>\n  );\n}\n","frontend/src/app/dashboard/billing/page.tsx":"\"use client\";\n﻿\"use client\";\n// Path: frontend/src/app/dashboard/billing/page.tsx\n\nimport { useState } from \"react\";\nimport { motion } from \"framer-motion\";\nimport { useTheme } from \"../../../components/layout/DashboardLayout\";\nimport { Check, Zap, Crown, ArrowUpRight, CreditCard, Receipt, ChevronRight, Shield, Sparkles } from \"lucide-react\";\nimport { useAuthStore } from \"../../../store/auth.store\";\nimport { useMutation } from \"@tanstack/react-query\";\nimport { api } from \"../../../lib/api\";\nimport toast from \"react-hot-toast\";\n\nconst V = { v900: \"#1A0D3D\", v700: \"#3D1C8A\", v600: \"#5428C8\", v500: \"#6B35E8\", v400: \"#8B5CF6\", v300: \"#A78BFA\", v200: \"#C4B5FD\", fuchsia: \"#C026D3\" };\nconst T = {\n  dark:  { card: \"#181230\", border: \"rgba(255,255,255,0.06)\", text: \"#fff\", muted: \"rgba(255,255,255,0.38)\", faint: \"rgba(255,255,255,0.04)\" },\n  light: { card: \"#fff\",    border: \"rgba(15,5,32,0.07)\",    text: \"#0D0918\", muted: \"rgba(13,9,24,0.45)\", faint: \"rgba(15,5,32,0.03)\" },\n};\n\nconst PLANS = [\n  {\n    id: \"FREE\", name: \"Free\", price: { ngn: 0, gbp: 0, usd: 0 },\n    icon: Sparkles, color: \"#6B7280\",\n    features: [\"1 store\", \"20 products\", \"KIRO 10 msgs/day\", \"Basic analytics\", \"2% transaction fee\", \"Community support\"],\n    limit: true,\n  },\n  {\n    id: \"GROWTH\", name: \"Growth\", price: { ngn: 9500, gbp: 12, usd: 15 },\n    icon: Zap, color: V.v400,\n    features: [\"1 store\", \"Unlimited products\", \"Full KIRO access\", \"Advanced analytics\", \"Custom domain\", \"1.5% transaction fee\", \"Email support 24hr\", \"Coupons & flash sales\", \"Abandoned cart recovery\"],\n    popular: true,\n  },\n  {\n    id: \"PRO\", name: \"Pro\", price: { ngn: 25000, gbp: 35, usd: 45 },\n    icon: Crown, color: \"#F59E0B\",\n    features: [\"Unlimited stores\", \"Everything in Growth\", \"KIRO Pro intelligence\", \"WhatsApp commerce bot\", \"1% transaction fee\", \"Email campaigns\", \"Loyalty programme\", \"3 staff accounts\", \"API access\", \"Priority support 2hr\"],\n  },\n];\n\nconst CURRENCY_LABELS: Record<string, string> = { ngn: \"₦\", gbp: \"£\", usd: \"$\" };\n\nexport default function BillingPage() {\n  const { theme } = useTheme();\n  const t = theme === \"dark\" ? T.dark : T.light;\n  const { user } = useAuthStore();\n  const [billing, setBilling] = useState<\"monthly\" | \"annual\">(\"monthly\");\n  const [currency, setCurrency] = useState<\"ngn\" | \"gbp\" | \"usd\">(\"ngn\");\n  const currentPlan = user?.subscription?.plan || \"FREE\";\n\n  const upgradeMut = useMutation({\n    mutationFn: async (planId: string) => {\n      const price = PLANS.find(p => p.id === planId)?.price[currency] || 0;\n      const amount = billing === \"annual\" ? Math.round(price * 10) : price; // 10 months for annual (2 free)\n      return api.post(\"/billing/upgrade\", { plan: planId, currency, billing, amount });\n    },\n    onSuccess: (res) => {\n      const url = res.data?.data?.authorizationUrl || res.data?.data?.url;\n      if (url) { window.location.href = url; }\n      else { toast.success(\"Plan updated!\"); }\n    },\n    onError: (e: any) => toast.error(e.response?.data?.message || \"Upgrade failed - backend offline\"),\n  });\n\n  const handleUpgrade = (planId: string) => {\n    if (planId === \"FREE\") return;\n    if (planId === currentPlan) { toast.success(\"You are already on this plan\"); return; }\n    const plan = PLANS.find(p => p.id === planId);\n    const price = plan?.price[currency] || 0;\n    const msg = billing === \"annual\"\n      ? `Upgrade to ${plan?.name} — ${CURRENCY_LABELS[currency]}${(price * 10).toLocaleString()}/year (2 months free)`\n      : `Upgrade to ${plan?.name} — ${CURRENCY_LABELS[currency]}${price.toLocaleString()}/month`;\n    toast.loading(msg, { duration: 2000 });\n    setTimeout(() => upgradeMut.mutate(planId), 400);\n  };\n\n  return (\n    <div style={{ maxWidth: 1100, margin: \"0 auto\" }}>\n      {/* Header */}\n      <motion.div initial={{ opacity: 0, y: -8 }} animate={{ opacity: 1, y: 0 }}\n        style={{ display: \"flex\", alignItems: \"flex-start\", justifyContent: \"space-between\", gap: 16, marginBottom: 32 }}>\n        <div>\n          <h1 style={{ fontSize: 22, fontWeight: 800, letterSpacing: \"-0.03em\", color: t.text }}>Billing & Plans</h1>\n          <p style={{ fontSize: 13, color: t.muted, marginTop: 4 }}>Manage your subscription and payment details</p>\n        </div>\n        <div style={{ display: \"flex\", gap: 8 }}>\n          <button style={{ display: \"flex\", alignItems: \"center\", gap: 6, padding: \"9px 14px\", borderRadius: 11, border: `1px solid ${t.border}`, background: \"transparent\", cursor: \"pointer\", fontSize: 13, color: t.muted }}>\n            <Receipt size={13} /> View Invoices\n          </button>\n        </div>\n      </motion.div>\n\n      {/* Current plan banner */}\n      <motion.div initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.1 }}\n        style={{ padding: \"18px 22px\", borderRadius: 16, marginBottom: 28, background: \"rgba(107,53,232,0.08)\", border: \"1px solid rgba(107,53,232,0.2)\", display: \"flex\", alignItems: \"center\", gap: 14 }}>\n        <div style={{ width: 40, height: 40, borderRadius: 12, display: \"flex\", alignItems: \"center\", justifyContent: \"center\", background: `linear-gradient(145deg, ${V.v500}, ${V.v900})`, boxShadow: \"0 4px 14px rgba(107,53,232,0.3)\" }}>\n          <Zap size={18} color=\"white\" />\n        </div>\n        <div style={{ flex: 1 }}>\n          <div style={{ fontSize: 14, fontWeight: 700, color: t.text }}>You're on the <span style={{ color: V.v300 }}>{currentPlan}</span> plan</div>\n          <div style={{ fontSize: 12, color: t.muted, marginTop: 2 }}>Upgrade anytime. No contracts. Cancel anytime.</div>\n        </div>\n        <div style={{ display: \"flex\", alignItems: \"center\", gap: 8 }}>\n          <Shield size={13} color={V.v400} />\n          <span style={{ fontSize: 12, color: V.v400 }}>Secured by Paystack</span>\n        </div>\n      </motion.div>\n\n      {/* Billing toggle + currency */}\n      <div className=\"flex flex-wrap items-center justify-center gap-3 mb-7\" style={{}}>\n        <div style={{ display: \"flex\", padding: 3, borderRadius: 12, background: t.card, border: `1px solid ${t.border}` }}>\n          {([\"monthly\", \"annual\"] as const).map(b => (\n            <button key={b} onClick={() => setBilling(b)}\n              style={{ padding: \"7px 20px\", borderRadius: 10, border: \"none\", cursor: \"pointer\", fontSize: 13, fontWeight: billing === b ? 600 : 400, background: billing === b ? (theme === \"dark\" ? \"rgba(107,53,232,0.25)\" : \"rgba(107,53,232,0.12)\") : \"transparent\", color: billing === b ? (theme === \"dark\" ? V.v200 : V.v600) : t.muted, transition: \"all 0.15s\" }}>\n              {b === \"monthly\" ? \"Monthly\" : \"Annual\"}{b === \"annual\" && <span style={{ marginLeft: 6, fontSize: 10, fontWeight: 700, padding: \"1px 5px\", borderRadius: 4, background: \"rgba(16,185,129,0.2)\", color: \"#10B981\" }}>-17%</span>}\n            </button>\n          ))}\n        </div>\n        <div style={{ display: \"flex\", padding: 3, borderRadius: 12, background: t.card, border: `1px solid ${t.border}` }}>\n          {([\"ngn\", \"gbp\", \"usd\"] as const).map(c => (\n            <button key={c} onClick={() => setCurrency(c)}\n              style={{ padding: \"7px 14px\", borderRadius: 10, border: \"none\", cursor: \"pointer\", fontSize: 13, fontWeight: currency === c ? 600 : 400, background: currency === c ? (theme === \"dark\" ? \"rgba(107,53,232,0.25)\" : \"rgba(107,53,232,0.12)\") : \"transparent\", color: currency === c ? (theme === \"dark\" ? V.v200 : V.v600) : t.muted, transition: \"all 0.15s\" }}>\n              {CURRENCY_LABELS[c]}{c.toUpperCase()}\n            </button>\n          ))}\n        </div>\n      </div>\n\n      {/* Plan cards */}\n      <div className=\"grid grid-cols-1 md:grid-cols-3 gap-4 mb-8\" style={{}}>\n        {PLANS.map((plan, i) => {\n          const Icon = plan.icon;\n          const isCurrent = currentPlan === plan.id;\n          const price = billing === \"annual\" ? Math.round(plan.price[currency] * 10) : plan.price[currency];\n          const isPopular = plan.popular;\n\n          return (\n            <motion.div key={plan.id} initial={{ opacity: 0, y: 16 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: i * 0.1 }}\n              style={{ padding: 24, borderRadius: 20, position: \"relative\", overflow: \"hidden\", background: isPopular ? `linear-gradient(145deg, ${V.v900} 0%, #110D22 100%)` : t.card, border: `1px solid ${isPopular ? \"rgba(107,53,232,0.4)\" : isCurrent ? \"rgba(107,53,232,0.25)\" : t.border}`, boxShadow: isPopular ? \"0 8px 32px rgba(107,53,232,0.25)\" : theme === \"light\" ? \"0 1px 3px rgba(15,5,32,0.04), 0 4px 20px rgba(15,5,32,0.03)\" : \"none\" }}>\n\n              {/* Glow for popular */}\n              {isPopular && <div style={{ position: \"absolute\", top: -60, right: -60, width: 200, height: 200, borderRadius: \"50%\", background: \"radial-gradient(circle, rgba(107,53,232,0.2) 0%, transparent 70%)\", pointerEvents: \"none\" }} />}\n\n              {/* Popular badge */}\n              {isPopular && (\n                <div style={{ position: \"absolute\", top: 14, right: 14, fontFamily: \"'Syncopate', sans-serif\", fontSize: 7.5, fontWeight: 700, letterSpacing: \"0.1em\", padding: \"4px 8px\", borderRadius: 6, background: `linear-gradient(135deg, ${V.v500}, ${V.fuchsia})`, color: \"white\" }}>POPULAR</div>\n              )}\n\n              {/* Current badge */}\n              {isCurrent && !isPopular && (\n                <div style={{ position: \"absolute\", top: 14, right: 14, fontFamily: \"'Syncopate', sans-serif\", fontSize: 7.5, fontWeight: 700, letterSpacing: \"0.1em\", padding: \"4px 8px\", borderRadius: 6, background: \"rgba(16,185,129,0.15)\", color: \"#10B981\", border: \"1px solid rgba(16,185,129,0.25)\" }}>CURRENT</div>\n              )}\n\n              {/* Plan icon */}\n              <div style={{ width: 44, height: 44, borderRadius: 14, display: \"flex\", alignItems: \"center\", justifyContent: \"center\", marginBottom: 16, background: `${plan.color}20`, border: `1px solid ${plan.color}30` }}>\n                <Icon size={20} color={plan.color} />\n              </div>\n\n              <div style={{ fontFamily: \"'Syncopate', sans-serif\", fontSize: 11, fontWeight: 700, letterSpacing: \"0.1em\", color: plan.color, marginBottom: 6 }}>{plan.name.toUpperCase()}</div>\n\n              <div style={{ marginBottom: 20 }}>\n                <span style={{ fontSize: 32, fontWeight: 800, letterSpacing: \"-0.04em\", color: isPopular ? \"#fff\" : t.text }}>\n                  {CURRENCY_LABELS[currency]}{price === 0 ? \"0\" : price.toLocaleString()}\n                </span>\n                {price > 0 && <span style={{ fontSize: 13, color: isPopular ? \"rgba(255,255,255,0.45)\" : t.muted }}>/mo</span>}\n                {price === 0 && <span style={{ fontSize: 13, color: isPopular ? \"rgba(255,255,255,0.45)\" : t.muted }}> forever</span>}\n                {billing === \"annual\" && price > 0 && <div style={{ fontSize: 11, color: \"#10B981\", marginTop: 3 }}>Billed annually · 2 months free</div>}\n              </div>\n\n              {/* CTA */}\n              <button\n                disabled={isCurrent || upgradeMut.isPending}\n                onClick={() => !isCurrent && handleUpgrade(plan.id)}\n                style={{ width: \"100%\", padding: \"11px\", borderRadius: 12, border: isCurrent ? `1px solid ${t.border}` : \"none\", cursor: isCurrent ? \"default\" : \"pointer\", fontSize: 13, fontWeight: 700, marginBottom: 20, background: isCurrent ? \"transparent\" : isPopular ? `linear-gradient(135deg, ${V.v500}, ${V.v700})` : `${plan.color}15`, color: isCurrent ? t.muted : isPopular ? \"white\" : plan.color, boxShadow: isPopular && !isCurrent ? \"0 4px 16px rgba(107,53,232,0.35)\" : \"none\", transition: \"all 0.15s\", opacity: upgradeMut.isPending ? 0.7 : 1 }}>\n                {upgradeMut.isPending && upgradeMut.variables === plan.id ? \"Opening Paystack...\" : isCurrent ? \"Current Plan\" : plan.id === \"FREE\" ? \"Downgrade\" : `Upgrade to ${plan.name}`}\n              </button>\n\n              {/* Features */}\n              <div style={{ display: \"flex\", flexDirection: \"column\", gap: 8 }}>\n                {plan.features.map(f => (\n                  <div key={f} style={{ display: \"flex\", alignItems: \"center\", gap: 8 }}>\n                    <div style={{ width: 16, height: 16, borderRadius: \"50%\", display: \"flex\", alignItems: \"center\", justifyContent: \"center\", background: `${plan.color}20`, flexShrink: 0 }}>\n                      <Check size={9} color={plan.color} />\n                    </div>\n                    <span style={{ fontSize: 12, color: isPopular ? \"rgba(255,255,255,0.7)\" : t.muted }}>{f}</span>\n                  </div>\n                ))}\n              </div>\n            </motion.div>\n          );\n        })}\n      </div>\n\n      {/* Payment method */}\n      <motion.div initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.4 }}\n        style={{ padding: 20, borderRadius: 16, background: t.card, border: `1px solid ${t.border}`, display: \"flex\", alignItems: \"center\", gap: 14 }}>\n        <div style={{ width: 40, height: 40, borderRadius: 12, display: \"flex\", alignItems: \"center\", justifyContent: \"center\", background: t.faint, border: `1px solid ${t.border}` }}>\n          <CreditCard size={18} color={t.muted} />\n        </div>\n        <div style={{ flex: 1 }}>\n          <div style={{ fontSize: 13, fontWeight: 600, color: t.text }}>No payment method added</div>\n          <div style={{ fontSize: 12, color: t.muted, marginTop: 2 }}>Add a card or bank account to upgrade your plan</div>\n        </div>\n        <button style={{ display: \"flex\", alignItems: \"center\", gap: 6, padding: \"8px 16px\", borderRadius: 10, border: \"none\", cursor: \"pointer\", background: `linear-gradient(135deg, ${V.v500}, ${V.v700})`, color: \"white\", fontSize: 13, fontWeight: 600, boxShadow: \"0 4px 12px rgba(107,53,232,0.3)\" }}>\n          Add Payment Method <ChevronRight size={13} />\n        </button>\n      </motion.div>\n    </div>\n  );\n}\n","frontend/src/app/dashboard/settings/page.tsx":"\"use client\";\nimport { useState } from \"react\";\nimport { motion } from \"framer-motion\";\nimport { useTheme, useToast, useConfirm } from \"../../../components/layout/DashboardLayout\";\nimport { useAuthStore } from \"../../../store/auth.store\";\nimport { api } from \"../../../lib/api\";\nimport toast from \"react-hot-toast\";\nimport { User, Bell, Shield, Palette, Globe, Trash2, Eye, EyeOff, ChevronRight, Camera, Sun, Moon, Check } from \"lucide-react\";\n\nconst V = { v500: \"#6B35E8\", v400: \"#8B5CF6\", v300: \"#A78BFA\" };\nconst T = {\n  dark:  { card: \"#181230\", border: \"rgba(255,255,255,0.06)\", text: \"#fff\", muted: \"rgba(255,255,255,0.38)\", faint: \"rgba(255,255,255,0.04)\", input: \"rgba(255,255,255,0.05)\" },\n  light: { card: \"#fff\",    border: \"rgba(15,5,32,0.07)\",    text: \"#0D0918\", muted: \"rgba(13,9,24,0.45)\", faint: \"rgba(15,5,32,0.03)\", input: \"rgba(15,5,32,0.04)\" },\n};\n\nconst SECTIONS = [\n  { id: \"profile\",       label: \"Profile\",      icon: User    },\n  { id: \"notifications\", label: \"Alerts\",       icon: Bell    },\n  { id: \"security\",      label: \"Security\",     icon: Shield  },\n  { id: \"appearance\",    label: \"Appearance\",   icon: Palette },\n  { id: \"domain\",        label: \"Domain\",        icon: Globe   },\n  { id: \"danger\",        label: \"Danger Zone\",  icon: Trash2  },\n];\n\nfunction SettingRow({ label, desc, children, t }: any) {\n  return (\n    <div className=\"flex items-center justify-between py-4 gap-4\" style={{ borderBottom: `1px solid ${t.border}` }}>\n      <div className=\"flex-1 min-w-0\">\n        <p className=\"text-sm font-semibold\" style={{ color: t.text }}>{label}</p>\n        {desc && <p className=\"text-xs mt-0.5\" style={{ color: t.muted }}>{desc}</p>}\n      </div>\n      <div className=\"flex-shrink-0\">{children}</div>\n    </div>\n  );\n}\n\nfunction Toggle({ value, onChange }: { value: boolean; onChange: (v: boolean) => void }) {\n  return (\n    <button onClick={() => onChange(!value)}\n      className=\"relative flex-shrink-0 transition-all\"\n      style={{ width: 44, height: 24, borderRadius: 12, border: \"none\", cursor: \"pointer\", background: value ? V.v500 : \"rgba(128,128,128,0.2)\" }}>\n      <div className=\"absolute top-0.5 w-5 h-5 rounded-full bg-white transition-all shadow-sm\" style={{ left: value ? 22 : 2 }} />\n    </button>\n  );\n}\n\nfunction TextInput({ label, value, onChange, type = \"text\", placeholder, t, disabled }: any) {\n  const [show, setShow] = useState(false);\n  return (\n    <div>\n      <label className=\"block text-xs font-semibold mb-1.5\" style={{ color: t.muted }}>{label}</label>\n      <div className=\"relative\">\n        <input\n          type={type === \"password\" ? (show ? \"text\" : \"password\") : type}\n          value={value} onChange={e => onChange(e.target.value)}\n          placeholder={placeholder} disabled={disabled}\n          className=\"w-full px-4 py-3 rounded-xl text-sm outline-none\"\n          style={{ border: `1px solid ${t.border}`, background: disabled ? t.faint : t.input, color: t.text, fontFamily: \"inherit\", paddingRight: type === \"password\" ? 44 : 16, opacity: disabled ? 0.6 : 1 }}\n        />\n        {type === \"password\" && (\n          <button type=\"button\" onClick={() => setShow(!show)} className=\"absolute right-3 top-1/2 -translate-y-1/2\" style={{ border: \"none\", background: \"none\", cursor: \"pointer\", color: t.muted }}>\n            {show ? <EyeOff size={14} /> : <Eye size={14} />}\n          </button>\n        )}\n      </div>\n    </div>\n  );\n}\n\n\nfunction DomainSection({ t, storeId }: { t: any; storeId?: string }) {\n  const [domain, setDomain] = useState(\"\");\n  const [saving, setSaving] = useState(false);\n  const [verified, setVerified] = useState(false);\n\n  const save = async () => {\n    if (!domain.trim()) return;\n    setSaving(true);\n    try {\n      const { api } = await import(\"../../../lib/api\");\n      await api.put(`/stores/${storeId}/custom-domain`, { domain: domain.trim().toLowerCase() });\n      setVerified(true);\n      toast.success(\"Domain saved! Now add the CNAME record below to your DNS.\");\n    } catch {\n      toast.error(\"Backend offline — save your domain when Render is live\");\n    } finally { setSaving(false); }\n  };\n\n  return (\n    <div className=\"space-y-4\">\n      <div>\n        <label className=\"block text-xs font-semibold mb-2\" style={{ color: t.muted }}>Custom domain</label>\n        <div className=\"flex gap-2\">\n          <input value={domain} onChange={e => setDomain(e.target.value)} placeholder=\"store.yourbrand.com\"\n            className=\"flex-1 px-4 py-2.5 rounded-xl text-sm outline-none\"\n            style={{ background: t.faint, border: `1px solid ${t.border}`, color: t.text, fontFamily: \"inherit\" }}/>\n          <button onClick={save} disabled={!domain.trim() || saving}\n            className=\"px-4 py-2.5 rounded-xl text-sm font-bold text-white disabled:opacity-50\"\n            style={{ background: \"linear-gradient(135deg,#6B35E8,#3D1C8A)\", border: \"none\", cursor: \"pointer\" }}>\n            {saving ? \"Saving...\" : \"Save\"}\n          </button>\n        </div>\n        <p className=\"text-xs mt-1.5\" style={{ color: t.muted }}>Must be a subdomain you control (e.g. shop.yourbrand.com)</p>\n      </div>\n      {(verified || domain) && (\n        <div className=\"p-4 rounded-xl space-y-2\" style={{ background: \"rgba(107,53,232,0.06)\", border: \"1px solid rgba(107,53,232,0.2)\" }}>\n          <p className=\"text-xs font-bold\" style={{ color: \"#A78BFA\" }}>Add this CNAME record to your DNS:</p>\n          <div className=\"grid grid-cols-2 gap-2 text-xs\">\n            <div><p style={{ color: t.muted, marginBottom: 2 }}>Type</p><p className=\"font-mono font-bold\" style={{ color: t.text }}>CNAME</p></div>\n            <div><p style={{ color: t.muted, marginBottom: 2 }}>Name</p><p className=\"font-mono font-bold\" style={{ color: t.text }}>{domain.split(\".\")[0] || \"store\"}</p></div>\n            <div className=\"col-span-2\"><p style={{ color: t.muted, marginBottom: 2 }}>Value</p><p className=\"font-mono font-bold text-xs\" style={{ color: t.text }}>cname.vercel-dns.com</p></div>\n          </div>\n          <p className=\"text-xs\" style={{ color: t.muted }}>DNS changes take 10-60 minutes to propagate. SSL is automatic via Vercel.</p>\n        </div>\n      )}\n    </div>\n  );\n}\n\nexport default function SettingsPage() {\n  const { theme, toggle: toggleTheme } = useTheme();\n  const { show } = useToast();\n  const { confirm } = useConfirm();\n  const { user } = useAuthStore();\n  const isDark = theme === \"dark\";\n  const t = isDark ? T.dark : T.light;\n\n  const [activeSection, setActiveSection] = useState(\"profile\");\n  const [saving, setSaving] = useState(false);\n  const [name, setName]   = useState(user?.name || \"\");\n  const [email, setEmail] = useState(user?.email || \"\");\n  const [currentPw, setCurrentPw] = useState(\"\");\n  const [newPw, setNewPw]         = useState(\"\");\n  const [notifs, setNotifs] = useState({ orders: true, marketing: false, security: true, updates: true, kiro: true });\n\n  const handleSaveProfile = async () => {\n    setSaving(true);\n    try { await api.put(\"/auth/profile\", { name, email }); show(\"Profile saved\", \"success\"); }\n    catch { show(\"Saved locally (backend offline)\", \"info\"); }\n    finally { setSaving(false); }\n  };\n\n  const handleChangePassword = async () => {\n    if (!currentPw || !newPw) { show(\"Fill in both fields\", \"error\"); return; }\n    try { await api.put(\"/auth/password\", { currentPassword: currentPw, newPassword: newPw }); show(\"Password updated\", \"success\"); setCurrentPw(\"\"); setNewPw(\"\"); }\n    catch (e: any) { show(e.response?.data?.message || \"Failed\", \"error\"); }\n  };\n\n  const handleDelete = async () => {\n    const ok = await confirm({ title: \"Delete your account?\", message: \"This permanently deletes your account and all store data. Cannot be undone.\", confirmText: \"Yes, delete everything\", cancelText: \"Keep my account\", variant: \"danger\" });\n    if (ok) show(\"Account deletion requested\", \"info\");\n  };\n\n  return (\n    <div className=\"max-w-4xl mx-auto\">\n      <motion.div initial={{ opacity: 0, y: -8 }} animate={{ opacity: 1, y: 0 }} className=\"mb-6\">\n        <h1 className=\"text-xl sm:text-2xl font-black tracking-tight\" style={{ color: t.text }}>Settings</h1>\n        <p className=\"text-xs sm:text-sm mt-1\" style={{ color: t.muted }}>Manage your account and preferences</p>\n      </motion.div>\n\n      <div className=\"flex flex-col sm:flex-row gap-4\">\n        {/* Section sidebar - horizontal scroll on mobile, vertical on desktop */}\n        <div className=\"sm:w-44 flex-shrink-0\">\n          <div className=\"flex sm:flex-col gap-1 overflow-x-auto pb-1 sm:pb-0\" style={{ scrollbarWidth: \"none\" }}>\n            {SECTIONS.map(s => {\n              const Icon = s.icon;\n              const active = activeSection === s.id;\n              return (\n                <button key={s.id} onClick={() => setActiveSection(s.id)}\n                  className=\"flex items-center gap-2.5 px-3 py-2.5 rounded-xl text-left transition-all whitespace-nowrap sm:whitespace-normal flex-shrink-0 sm:flex-shrink w-auto sm:w-full\"\n                  style={{ background: active ? \"rgba(107,53,232,0.1)\" : \"transparent\", border: `1px solid ${active ? \"rgba(107,53,232,0.25)\" : \"transparent\"}`, color: active ? V.v300 : t.muted }}>\n                  <Icon size={14} />\n                  <span className=\"text-xs font-semibold\">{s.label}</span>\n                </button>\n              );\n            })}\n          </div>\n        </div>\n\n        {/* Content */}\n        <div className=\"flex-1 min-w-0\">\n          <motion.div key={activeSection} initial={{ opacity: 0, x: 8 }} animate={{ opacity: 1, x: 0 }} transition={{ duration: 0.15 }}\n            className=\"rounded-2xl p-4 sm:p-6\" style={{ background: t.card, border: `1px solid ${t.border}` }}>\n\n            {activeSection === \"profile\" && (\n              <div className=\"space-y-4\">\n                <h2 className=\"text-sm font-bold mb-4\" style={{ color: t.text }}>Profile</h2>\n                {/* Avatar */}\n                <div className=\"flex items-center gap-4 mb-2\">\n                  <div className=\"relative\">\n                    <div className=\"w-16 h-16 rounded-2xl flex items-center justify-center text-2xl font-black text-white\" style={{ background: \"linear-gradient(135deg,#6B35E8,#3D1C8A)\" }}>\n                      {name?.[0]?.toUpperCase() || \"U\"}\n                    </div>\n                    <button className=\"absolute -bottom-1 -right-1 w-6 h-6 rounded-full flex items-center justify-center text-white\" style={{ background: V.v500 }}>\n                      <Camera size={10} />\n                    </button>\n                  </div>\n                  <div>\n                    <p className=\"text-sm font-semibold\" style={{ color: t.text }}>{name || \"Your Name\"}</p>\n                    <p className=\"text-xs\" style={{ color: t.muted }}>{email}</p>\n                  </div>\n                </div>\n                <TextInput label=\"Full Name\" value={name} onChange={setName} placeholder=\"Your name\" t={t} />\n                <TextInput label=\"Email\" value={email} onChange={setEmail} type=\"email\" placeholder=\"you@example.com\" t={t} />\n                <button onClick={handleSaveProfile} disabled={saving}\n                  className=\"w-full sm:w-auto px-6 py-2.5 rounded-xl text-sm font-bold text-white flex items-center justify-center gap-2 disabled:opacity-60\"\n                  style={{ background: \"linear-gradient(135deg,#6B35E8,#3D1C8A)\" }}>\n                  {saving ? \"Saving...\" : \"Save Profile\"}\n                </button>\n              </div>\n            )}\n\n            {activeSection === \"notifications\" && (\n              <div>\n                <h2 className=\"text-sm font-bold mb-1\" style={{ color: t.text }}>Notification Preferences</h2>\n                <p className=\"text-xs mb-4\" style={{ color: t.muted }}>Choose what you want to be notified about</p>\n                {[\n                  { key: \"orders\",    label: \"New Orders\",          desc: \"Get notified when a customer places an order\" },\n                  { key: \"kiro\",      label: \"KIRO Alerts\",         desc: \"Morning briefs, opportunities, and urgent alerts\" },\n                  { key: \"security\",  label: \"Security Alerts\",     desc: \"Login attempts and account security\" },\n                  { key: \"marketing\", label: \"Marketing Tips\",      desc: \"Product ideas and growth suggestions\" },\n                  { key: \"updates\",   label: \"Platform Updates\",    desc: \"New features and improvements\" },\n                ].map(n => (\n                  <SettingRow key={n.key} label={n.label} desc={n.desc} t={t}>\n                    <Toggle value={notifs[n.key as keyof typeof notifs]} onChange={v => setNotifs(p => ({ ...p, [n.key]: v }))} />\n                  </SettingRow>\n                ))}\n              </div>\n            )}\n\n            {activeSection === \"security\" && (\n              <div className=\"space-y-4\">\n                <h2 className=\"text-sm font-bold mb-4\" style={{ color: t.text }}>Security</h2>\n                <TextInput label=\"Current Password\" value={currentPw} onChange={setCurrentPw} type=\"password\" placeholder=\"••••••••\" t={t} />\n                <TextInput label=\"New Password\" value={newPw} onChange={setNewPw} type=\"password\" placeholder=\"Min 8 characters\" t={t} />\n                <button onClick={handleChangePassword}\n                  className=\"w-full sm:w-auto px-6 py-2.5 rounded-xl text-sm font-bold text-white\"\n                  style={{ background: \"linear-gradient(135deg,#6B35E8,#3D1C8A)\" }}>\n                  Update Password\n                </button>\n                <div className=\"pt-4\" style={{ borderTop: `1px solid ${t.border}` }}>\n                  <SettingRow label=\"Two-Factor Authentication\" desc=\"Add an extra layer of security to your account\" t={t}>\n                    <button className=\"text-xs font-semibold px-3 py-1.5 rounded-lg\" style={{ border: `1px solid ${t.border}`, color: t.muted }}>Enable</button>\n                  </SettingRow>\n                </div>\n              </div>\n            )}\n\n            {activeSection === \"appearance\" && (\n              <div>\n                <h2 className=\"text-sm font-bold mb-4\" style={{ color: t.text }}>Appearance</h2>\n                <SettingRow label=\"Theme\" desc=\"Choose how the dashboard looks\" t={t}>\n                  <div className=\"flex gap-2\">\n                    {[{ mode: \"dark\", icon: Moon, label: \"Dark\" }, { mode: \"light\", icon: Sun, label: \"Light\" }].map(opt => {\n                      const Icon = opt.icon;\n                      const active = theme === opt.mode;\n                      return (\n                        <button key={opt.mode} onClick={toggleTheme}\n                          className=\"flex items-center gap-1.5 px-3 py-2 rounded-xl text-xs font-semibold transition-all\"\n                          style={{ background: active ? V.v500 : t.faint, color: active ? \"#fff\" : t.muted, border: `1px solid ${active ? V.v500 : t.border}` }}>\n                          <Icon size={12} /> {opt.label}\n                          {active && <Check size={11} />}\n                        </button>\n                      );\n                    })}\n                  </div>\n                </SettingRow>\n              </div>\n            )}\n\n      \n      {activeSection === \"domain\" && (\n        <div className=\"space-y-0\" style={{ borderRadius: 16, overflow: \"hidden\", border: `1px solid ${t.border}` }}>\n          <div className=\"p-5\" style={{ borderBottom: `1px solid ${t.border}` }}>\n            <h2 className=\"font-bold text-sm mb-1\" style={{ color: t.text }}>Custom Domain</h2>\n            <p className=\"text-xs\" style={{ color: t.muted }}>Connect your own domain instead of the dropos.io subdomain</p>\n          </div>\n          <div className=\"p-5 space-y-4\">\n            <div>\n              <label className=\"block text-xs font-semibold mb-2\" style={{ color: t.muted }}>Your subdomain (always free)</label>\n              <div className=\"flex items-center gap-2 px-4 py-2.5 rounded-xl\" style={{ background: t.faint, border: `1px solid ${t.border}` }}>\n                <span className=\"text-sm font-semibold\" style={{ color: t.text }}>{user?.stores?.[0]?.slug || \"yourstore\"}</span>\n                <span className=\"text-sm\" style={{ color: t.muted }}>.droposhq.com</span>\n              </div>\n            </div>\n            <DomainSection t={t} storeId={user?.stores?.[0]?.id} />\n          </div>\n        </div>\n      )}\n\n      {activeSection === \"danger\" && (\n              <div>\n                <h2 className=\"text-sm font-bold mb-1 text-red-400\">Danger Zone</h2>\n                <p className=\"text-xs mb-6\" style={{ color: t.muted }}>These actions cannot be undone. Be very careful.</p>\n                <div className=\"p-4 rounded-2xl\" style={{ border: \"1px solid rgba(239,68,68,0.25)\", background: \"rgba(239,68,68,0.05)\" }}>\n                  <p className=\"text-sm font-semibold text-red-400 mb-1\">Delete Account</p>\n                  <p className=\"text-xs mb-4\" style={{ color: t.muted }}>Permanently delete your account and all store data including products, orders, and customer information.</p>\n                  <button onClick={handleDelete} className=\"px-4 py-2 rounded-xl text-xs font-bold text-white\" style={{ background: \"#EF4444\" }}>\n                    Delete My Account\n                  </button>\n                </div>\n              </div>\n            )}\n\n          </motion.div>\n        </div>\n      </div>\n    </div>\n  );\n}\n"};
let n=0;
for(const [rel,content] of Object.entries(files)){
  const p=rel.replace(/\//g,path.sep);
  fs.mkdirSync(path.dirname(p),{recursive:true});
  fs.writeFileSync(p,content,'utf8');
  console.log('OK',rel.split('/').slice(-2).join('/'));n++;
}
console.log('Written:',n,'files');
try{
  execSync('git add .',{stdio:'inherit'});
  const st=execSync('git status --short',{encoding:'utf8'}).trim();
  if(st){
    execSync('git commit -m "feat: Phase 9 - Public KIRO page with auth wall, KIRO action icons + smart prompts, billing upgrade toast, custom domain settings"',{stdio:'inherit'});
    execSync('git push origin main',{stdio:'inherit'});
    console.log('Pushed. Vercel deploying.');
  } else { console.log('Run: git push origin main'); }
}catch(e){console.log('Git:',e.message);}
